//! # Encoder Config with Saturation Integration
//!
//! Extends the rknot encoder to accept and embed saturation maps from the
//! profiling phase. When encoding a .knot → .rknot, the encoder can optionally:
//!
//! 1. Include saturation bitmasks in RknotHeader
//! 2. Zero out frozen neurons in weights (optional optimization)
//! 3. Update encoder stats to reflect saturation-based optimizations

use super::saturation_metadata::SaturationMaps;

/// Configuration for encoding a .knot file into .rknot format,
/// with optional saturation map integration.
#[derive(Debug, Clone)]
pub struct KnotEncoderConfig {
    /// Encoder version identifier (e.g., "rknot-encoder/0.2.0")
    pub encoder_version: String,

    /// Optional probe corpus used for manifest calibration
    pub calibration_probe: Option<String>,

    /// Optional saturation maps from the profiling phase.
    /// If present, these will be embedded in the .rknot header
    /// and inference kernels can use them for sparse FFN computation.
    pub saturation_maps: Option<SaturationMaps>,

    /// If true, zero out frozen neurons in FFN weight blocks
    /// before quantization (applies sparsity at encode time).
    /// Default: false (embed bitmasks for runtime sparse ops only).
    pub apply_saturation_pruning: bool,

    /// If true, report per-layer saturation statistics in logs
    /// (helps validate that embedded masks are sensible).
    pub log_saturation_stats: bool,
}

impl KnotEncoderConfig {
    /// Creates a minimal encoder config with defaults.
    pub fn new(encoder_version: String) -> Self {
        Self {
            encoder_version,
            calibration_probe: None,
            saturation_maps: None,
            apply_saturation_pruning: false,
            log_saturation_stats: false,
        }
    }

    /// Sets the calibration probe.
    pub fn with_calibration_probe(mut self, probe: String) -> Self {
        self.calibration_probe = Some(probe);
        self
    }

    /// Embeds saturation maps in the encoder output.
    pub fn with_saturation_maps(mut self, maps: SaturationMaps) -> Self {
        self.saturation_maps = Some(maps);
        self
    }

    /// Enables runtime saturation pruning (zero out frozen neurons before encoding).
    pub fn with_pruning_enabled(mut self, enabled: bool) -> Self {
        self.apply_saturation_pruning = enabled;
        self
    }

    /// Enables saturation statistics logging.
    pub fn with_stats_logging(mut self, enabled: bool) -> Self {
        self.log_saturation_stats = enabled;
        self
    }

    /// Builder-style method to set all saturation-related flags.
    pub fn with_saturation(
        mut self,
        maps: SaturationMaps,
        apply_pruning: bool,
        log_stats: bool,
    ) -> Self {
        self.saturation_maps = Some(maps);
        self.apply_saturation_pruning = apply_pruning;
        self.log_saturation_stats = log_stats;
        self
    }

    /// Returns true if this config includes saturation data.
    pub fn has_saturation(&self) -> bool {
        self.saturation_maps.is_some()
    }

    /// Returns a summary string for logging.
    pub fn summary(&self) -> String {
        let sat_str = if let Some(maps) = &self.saturation_maps {
            format!("with {}", maps.summary())
        } else {
            "no saturation".to_string()
        };
        format!(
            "KnotEncoderConfig(version={}, saturation={}, pruning={}, log_stats={})",
            self.encoder_version, sat_str, self.apply_saturation_pruning, self.log_saturation_stats
        )
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::rknot::saturation_metadata::{LayerFrozenBitmask, SaturationMaps};

    #[test]
    fn encoder_config_basic() {
        let cfg = KnotEncoderConfig::new("rknot-encoder/0.2.0".to_string());
        assert!(!cfg.has_saturation());
        assert!(!cfg.apply_saturation_pruning);
        assert!(!cfg.log_saturation_stats);
    }

    #[test]
    fn encoder_config_with_saturation() {
        let maps = SaturationMaps::new(32, "variance+gradient".to_string());
        let cfg = KnotEncoderConfig::new("rknot-encoder/0.2.0".to_string())
            .with_saturation(maps, true, true);

        assert!(cfg.has_saturation());
        assert!(cfg.apply_saturation_pruning);
        assert!(cfg.log_saturation_stats);
    }

    #[test]
    fn encoder_config_builder() {
        let mut maps = SaturationMaps::new(32, "variance+gradient".to_string());
        maps = maps.insert_layer_mask(LayerFrozenBitmask::new(0, 8192));

        let cfg = KnotEncoderConfig::new("rknot-encoder/0.2.0".to_string())
            .with_calibration_probe("phi3-calib-corpus".to_string())
            .with_saturation_maps(maps)
            .with_pruning_enabled(true);

        assert!(cfg.calibration_probe.is_some());
        assert!(cfg.has_saturation());
        assert!(cfg.apply_saturation_pruning);
    }

    #[test]
    fn encoder_config_summary() {
        let cfg = KnotEncoderConfig::new("rknot-encoder/0.2.0".to_string());
        let summary = cfg.summary();
        assert!(summary.contains("rknot-encoder/0.2.0"));
        assert!(summary.contains("no saturation"));
    }
}
